<span class="line"><span style="color:#CDD6F4;">        success </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> result</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">is_ok</span><span style="color:#9399B2;">(),</span></span>
